// // This module implements a 4-bit down counter that decrements its value by 1 on each rising edge of the clock signal (clk). The counter resets to zero when the reset signal is low. When reset is high, the counter continues to count downwards from its current value.
module top_module(
  output reg [3:0] count,
  input clk,
  input reset
);always @(posedge clk or negedge reset) begin
    if(!reset) begin
      count <= 4'b0;
    end else begin
      count <= count + 1;
    end
  end

endmodule
